import React from 'react';
import { useParams, Link } from 'react-router-dom';
import './BlogDetail.css';

const BlogDetail = () => {
  const { slug } = useParams();

  const blogPosts = {
    '2023-autumn-statement': {
      id: 1,
      slug: '2023-autumn-statement',
      category: "Budget",
      title: "2023 Autumn Statement: What the Budget means for you",
      author: "Rayhaan Moughal",
      date: "23.11.2023",
      heroImage: "https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=1200&h=600&fit=crop",
      content: {
        introduction: "The 2023 Autumn Statement was positioned as a fiscal strategy geared towards reducing taxes and bolstering business growth. At Greyline Accountants Ltd, we're analysing what the announced measures mean for our clients and UK business owners.",
        keyAnnouncements: [
          "A reduction in National Insurance rates from 12% to 10% starting January 2024.",
          "Revisions to self-employment taxes, including the elimination of Class 2 NIC and a decrease in Class 4 NIC from 9% to 8%, effective April 2024.",
          "An increase in the National Living Wage to £11.44 per hour, effective from April 2024.",
          "Permanent Extension of Full Capital Expensing.",
          "Updates to the R&D tax credit scheme.",
          "No changes to tax thresholds."
        ],
        details: {
          nationalInsurance: {
            title: "National Insurance Rate Reduction",
            content: "The Chancellor announced a cut from 12% to 10% for Class 1 National Insurance Contributions, effective January 2024. This will benefit average employees and company directors, providing more take-home pay."
          },
